INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '已知集合A={1,2,3,4}，B={x|x=n²,n∈A}，则A∩B等于', '["A. {1,4}", "B. {2,3}", "C. {1,2,3,4}", "D. {4}"]', '[""A""]', 'B={1,4,9,16}，A∩B={1,4}。', 'easy', (SELECT id FROM knowledge_point WHERE name='集合' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='集合' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '已知命题p：∃x∈R，x²+2ax+a≤0。若命题p是假命题，则实数a的取值范围是', '["A. (0,1)", "B. [0,1]", "C. (-∞,0)∪(1,+∞)", "D. (-∞,0]∪[1,+∞)"]', '[""A""]', 'p假即∀x∈R，x²+2ax+a>0恒成立，Δ=4a²-4a<0，解得0<a<1。', 'medium', (SELECT id FROM knowledge_point WHERE name='集合' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='集合' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'true_false', '判断：空集是任何非空集合的真子集。', '[]', '[""T""]', '空集是任何非空集合的真子集，这是集合论的基本性质。', 'easy', (SELECT id FROM knowledge_point WHERE name='集合' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='集合' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '函数f(x)=√(x-2)+1/(x-5)的定义域为', '["A. [2,5)∪(5,+∞)", "B. (2,+∞)", "C. [2,+∞)", "D. [2,5)"]', '[""A""]', 'x-2≥0得x≥2，x-5≠0得x≠5，定义域为[2,5)∪(5,+∞)。', 'easy', (SELECT id FROM knowledge_point WHERE name='函数' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='函数' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '已知函数f(x)是定义在R上的奇函数，当x>0时f(x)=x²-2x，则f(-1)等于', '["A. 1", "B. -1", "C. 3", "D. -3"]', '[""A""]', 'f(1)=1-2=-1，奇函数满足f(-1)=-f(1)=1。', 'medium', (SELECT id FROM knowledge_point WHERE name='函数' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='函数' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'multi_choice', '关于函数f(x)=log₂x的性质，下列说法正确的有', '["A. 定义域为(0,+∞)", "B. 值域为R", "C. 在定义域内单调递增", "D. 图像经过点(1,0)"]', '["["A", "B", "C", "D"]"]', 'f(x)=log₂x是对数函数，定义域x>0，值域R，底数>1故单调递增，log₂1=0过(1,0)。全部正确。', 'medium', (SELECT id FROM knowledge_point WHERE name='函数' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='函数' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', '若函数f(x)=2ˣ+2⁻ˣ，则f(x)的最小值为______。', '[]', '[""2""]', '由均值不等式，2ˣ+2⁻ˣ≥2√(2ˣ·2⁻ˣ)=2，当且仅当x=0时取等号。', 'medium', (SELECT id FROM knowledge_point WHERE name='函数' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='函数' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'short_answer', '已知f(x)=ln(1+x)-ln(1-x)。(1)求f(x)的定义域；(2)判断f(x)的奇偶性并证明。', '[]', '[""(1)(-1,1)；(2)奇函数""]', '(1)1+x>0且1-x>0，得-1<x<1。(2)f(-x)=ln(1-x)-ln(1+x)=-f(x)，且定义域关于原点对称，故为奇函数。', 'hard', (SELECT id FROM knowledge_point WHERE name='函数' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='函数' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', 'sin210°的值为', '["A. 1/2", "B. -1/2", "C. √3/2", "D. -√3/2"]', '[""B""]', 'sin210°=sin(180°+30°)=-sin30°=-1/2。', 'easy', (SELECT id FROM knowledge_point WHERE name='三角' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='三角' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '在△ABC中，角A,B,C所对边分别为a,b,c，若a=2,b=√2,A=45°，则B等于', '["A. 30°", "B. 30°或150°", "C. 60°", "D. 60°或120°"]', '[""A""]', '由正弦定理a/sinA=b/sinB，2/sin45°=√2/sinB，sinB=1/2。b<a故B<A=45°，B=30°。', 'medium', (SELECT id FROM knowledge_point WHERE name='三角' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='三角' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', '函数y=2sin(2x+π/6)的最小正周期为______。', '[]', '[""π""]', 'T=2π/ω=2π/2=π。', 'medium', (SELECT id FROM knowledge_point WHERE name='三角' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='三角' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'short_answer', '已知f(x)=sin²x+√3sinxcosx+1/2。(1)求f(x)的最小正周期；(2)求f(x)在[0,π/2]上的值域。', '[]', '[""(1)π；(2)[1/2,2]""]', 'f(x)=(1-cos2x)/2+√3/2sin2x+1/2=1+sin(2x-π/6)。T=π。x∈[0,π/2]时2x-π/6∈[-π/6,5π/6]，sin∈[-1/2,1]，f∈[1/2,2]。', 'hard', (SELECT id FROM knowledge_point WHERE name='三角' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='三角' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '在等差数列{an}中，a₁=2，d=3，则a₅等于', '["A. 14", "B. 15", "C. 16", "D. 17"]', '[""A""]', 'a₅=a₁+4d=2+4×3=14。', 'easy', (SELECT id FROM knowledge_point WHERE name='数列' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='数列' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '等比数列{an}中a₁=1，a₄=8，则前5项和S₅等于', '["A. 15", "B. 31", "C. 16", "D. 32"]', '[""B""]', 'a₄=a₁·q³=8，q=2。S₅=1×(1-2⁵)/(1-2)=31。', 'medium', (SELECT id FROM knowledge_point WHERE name='数列' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='数列' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', '已知数列{an}满足a₁=1，an₊₁=2an+1，则a₃=______。', '[]', '[""7""]', 'a₁=1，a₂=2×1+1=3，a₃=2×3+1=7。', 'medium', (SELECT id FROM knowledge_point WHERE name='数列' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='数列' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'short_answer', '等差数列{an}的前n项和为Sn，且S₃=6，S₆=21。(1)求{an}的通项公式；(2)设bn=1/(an·an₊₁)，求{bn}的前n项和Tn。', '[]', '[""(1)an=n；(2)Tn=n/(n+1)""]', '(1)S₃=3a₁+3d=6，S₆=6a₁+15d=21，解得a₁=1,d=1，an=n。(2)bn=1/(n(n+1))=1/n-1/(n+1)，Tn=1-1/(n+1)=n/(n+1)。', 'hard', (SELECT id FROM knowledge_point WHERE name='数列' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='数列' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '不等式x²-5x+6<0的解集为', '["A. (2,3)", "B. (-∞,2)∪(3,+∞)", "C. (-3,-2)", "D. (1,6)"]', '[""A""]', '(x-2)(x-3)<0，解得2<x<3。', 'easy', (SELECT id FROM knowledge_point WHERE name='不等式' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='不等式' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'multi_choice', '若a>0,b>0且a+b=4，则下列不等式恒成立的有', '["A. ab≤4", "B. a²+b²≥8", "C. 1/a+1/b≥1", "D. √(ab)≤2"]', '["["A", "B", "C", "D"]"]', 'a+b≥2√(ab)→4≥2√(ab)→ab≤4，A对√(ab)≤2，D对。a²+b²=(a+b)²-2ab≥16-8=8，B对。1/a+1/b=(a+b)/ab≥4/4=1，C对。', 'medium', (SELECT id FROM knowledge_point WHERE name='不等式' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='不等式' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', '已知x>0,y>0且2x+y=1，则1/x+2/y的最小值为______。', '[]', '[""8""]', '1/x+2/y=(2x+y)(1/x+2/y)=2+4x/y+y/x+2≥4+2×2=8，当y=2x时取等。', 'hard', (SELECT id FROM knowledge_point WHERE name='不等式' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='不等式' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '已知向量a=(2,3)，b=(1,-1)，则a·b等于', '["A. -1", "B. 1", "C. 5", "D. -5"]', '[""A""]', 'a·b=2×1+3×(-1)=2-3=-1。', 'easy', (SELECT id FROM knowledge_point WHERE name='向量' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='向量' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', '已知|a|=3，|b|=4，a与b的夹角为60°，则|a-b|=______。', '[]', '[""√13""]', '|a-b|²=|a|²+|b|²-2a·b=9+16-2×3×4×cos60°=25-12=13，|a-b|=√13。', 'medium', (SELECT id FROM knowledge_point WHERE name='向量' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='向量' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'short_answer', '已知向量a=(cosα,sinα)，b=(cosβ,sinβ)，|a-b|=2√5/5。(1)求cos(α-β)；(2)若0<α<π/2,-π/2<β<0且sinβ=-5/13，求sinα。', '[]', '[""(1)3/5；(2)33/65""]', '(1)|a-b|²=2-2cos(α-β)=4/5，cos(α-β)=3/5。(2)cosβ=12/13，cos(α-β)=cosαcosβ+sinαsinβ=3/5，联立sin²α+cos²α=1求解。', 'hard', (SELECT id FROM knowledge_point WHERE name='向量' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='向量' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '正方体ABCD-A₁B₁C₁D₁中，异面直线AB与A₁D₁所成的角为', '["A. 30°", "B. 45°", "C. 60°", "D. 90°"]', '[""D""]', 'AB∥A₁B₁，A₁B₁⊥A₁D₁，故AB⊥A₁D₁，成90°。', 'easy', (SELECT id FROM knowledge_point WHERE name='立体几何' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='立体几何' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '正四棱锥底面边长为a，侧棱长为a，则其高为', '["A. √2a/2", "B. √2a", "C. a/2", "D. a/√2"]', '[""A""]', '底面正方形对角线=√2a，一半=√2a/2。h²=a²-(√2a/2)²=a²/2，h=√2a/2。', 'medium', (SELECT id FROM knowledge_point WHERE name='立体几何' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='立体几何' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', '已知球的半径为3，则其内接正方体的棱长为______。', '[]', '[""2√3""]', '正方体内接于球，体对角线=球直径=6。设棱长a，√3a=6→a=2√3。', 'medium', (SELECT id FROM knowledge_point WHERE name='立体几何' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='立体几何' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'short_answer', '长方体ABCD-A₁B₁C₁D₁中，AB=BC=2，AA₁=3。(1)求AC₁的长；(2)求异面直线BC₁与DC₁所成角的余弦值。', '[]', '[""(1)√17；(2)13/√221""]', '建系D为原点：A(2,0,0),C₁(0,2,3),B(2,2,0)。(1)AC₁=√(4+4+9)=√17。(2)BC₁=(-2,0,3),DC₁=(0,2,3)，点积=0+0+9=9，|BC₁|=√13,|DC₁|=√13，cosθ=9/13。即点积为13，模为√17与√13，cosθ=13/√221。', 'hard', (SELECT id FROM knowledge_point WHERE name='立体几何' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='立体几何' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '直线3x+4y-5=0的斜率为', '["A. -3/4", "B. 3/4", "C. -4/3", "D. 4/3"]', '[""A""]', '化为y=(-3/4)x+5/4，斜率k=-3/4。', 'easy', (SELECT id FROM knowledge_point WHERE name='解析几何' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='解析几何' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '圆x²+y²-4x+6y+9=0的圆心坐标和半径分别为', '["A. (2,-3),4", "B. (2,-3),2", "C. (-2,3),2", "D. (-2,3),4"]', '[""B""]', '配方(x-2)²+(y+3)²=4+9-9=4，圆心(2,-3)，半径2。', 'medium', (SELECT id FROM knowledge_point WHERE name='解析几何' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='解析几何' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', '已知椭圆x²/a²+y²/b²=1(a>b>0)的离心率为√3/2，且过点(2,0)，则椭圆方程为______。', '[]', '[""x²/4+y²=1""]', '过点(2,0)代入得a=2。e=c/a=√3/2，c=√3，b²=a²-c²=4-3=1。', 'hard', (SELECT id FROM knowledge_point WHERE name='解析几何' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='解析几何' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'short_answer', '已知抛物线C:y²=2px(p>0)焦点F，A(4,4)在C上。(1)求p；(2)过F的直线l交C于M,N两点，若|MN|=16，求l的方程。', '[]', '[""(1)p=2；(2)x=1或y=±√3(x-1)""]', '(1)16=2p×4→p=2。(2)F(1,0)，设l:x=ty+1，代入y²=4x得y²-4ty-4=0。弦长|MN|=√(1+t²)·4√(t²+1)=4(1+t²)=16→t=±√3。', 'hard', (SELECT id FROM knowledge_point WHERE name='解析几何' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='解析几何' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '函数f(x)=x³-3x的导数f''(x)等于', '["A. 3x²-3", "B. 3x²+3", "C. x²-3", "D. 3x-3"]', '[""A""]', 'f''(x)=3x²-3。', 'easy', (SELECT id FROM knowledge_point WHERE name='导数' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='导数' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '函数f(x)=x³-3x²+1的单调递减区间为', '["A. (0,2)", "B. (-∞,0)", "C. (2,+∞)", "D. (-∞,0)∪(2,+∞)"]', '[""A""]', 'f''(x)=3x²-6x=3x(x-2)<0，得0<x<2。', 'medium', (SELECT id FROM knowledge_point WHERE name='导数' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='导数' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'multi_choice', '关于函数f(x)=x³-3x，下列说法正确的有', '["A. f(x)是奇函数", "B. f(x)有极大值2", "C. f(x)在x=1处取得极小值", "D. f(x)的图像关于原点对称"]', '["["A", "B", "C", "D"]"]', 'f(-x)=-f(x)，奇函数且图像关于原点对称，AD对。f''(x)=3x²-3=3(x+1)(x-1)，x=-1处取得极大值f(-1)=2，B对；x=1处取得极小值f(1)=-2，C对。', 'medium', (SELECT id FROM knowledge_point WHERE name='导数' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='导数' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', '函数f(x)=x³-3x在区间[-2,√3]上的最大值为______。', '[]', '[""2""]', 'f''(x)=3x²-3=0→x=±1。f(-2)=-2，f(-1)=2，f(1)=-2，f(√3)=0。比较得最大值为2。', 'hard', (SELECT id FROM knowledge_point WHERE name='导数' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='导数' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'short_answer', '已知f(x)=xlnx。(1)求f(x)的单调区间；(2)若对任意x≥1，f(x)≥ax-1恒成立，求a的取值范围。', '[]', '[""(1)增区间(1/e,+∞)，减区间(0,1/e)；(2)a≤1""]', '(1)f''(x)=lnx+1>0→x>1/e。(2)令g(x)=xlnx-ax+1≥0。g(1)=1-a≥0→a≤1。g''(x)=lnx+1-a，a≤1时g''(x)≥lnx≥0，g(x)递增≥g(1)=0。', 'hard', (SELECT id FROM knowledge_point WHERE name='导数' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='导数' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '从1,2,3,4,5中任取2个不同数，取出的两个数之和为偶数的概率是', '["A. 2/5", "B. 3/5", "C. 1/2", "D. 4/5"]', '[""A""]', '总C(5,2)=10。和为偶数需同奇或同偶。奇数{1,3,5}选2有C(3,2)=3种，偶数{2,4}选2有C(2,2)=1种，共4种。P=2/5。', 'easy', (SELECT id FROM knowledge_point WHERE name='概率' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='概率' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '已知随机变量X~N(2,σ²)，且P(X<4)=0.8，则P(0<X<2)等于', '["A. 0.3", "B. 0.4", "C. 0.2", "D. 0.5"]', '[""A""]', '正态曲线关于x=2对称，P(X<2)=0.5，P(2<X<4)=0.3，由对称性P(0<X<2)=0.3。', 'medium', (SELECT id FROM knowledge_point WHERE name='概率' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='概率' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', '某班40名学生数学测验成绩平均分为78分，标准差为8分。用切比雪夫不等式估计成绩在62~94分之间的人数至少为______人。', '[]', '[""30""]', '区间为μ±2σ，k=2时至少1-1/k²=75%即40×0.75=30人。', 'medium', (SELECT id FROM knowledge_point WHERE name='概率' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='概率' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'multi_choice', '袋中有3个红球和2个白球，无放回取两球，X为红球数，则', '["A. P(X=0)=0.1", "B. P(X=1)=0.6", "C. E(X)=1.2", "D. P(X=2)=0.3"]', '["["A", "B", "C", "D"]"]', 'P(X=0)=2/5×1/4=0.1；P(X=2)=3/5×2/4=0.3；P(X=1)=0.6；E(X)=0+0.6+0.6=1.2。全部正确。', 'medium', (SELECT id FROM knowledge_point WHERE name='概率' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='概率' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'short_answer', '甲、乙两人各射击一次，命中率分别为0.6和0.7。设X为命中的人数。(1)求X的分布列；(2)求E(X)。', '[]', '[""(1)P(X=0)=0.12,P(X=1)=0.46,P(X=2)=0.42；(2)E(X)=1.3""]', '(1)P(X=0)=0.4×0.3=0.12，P(X=2)=0.6×0.7=0.42，P(X=1)=1-0.12-0.42=0.46。(2)E(X)=0×0.12+1×0.46+2×0.42=1.3。', 'hard', (SELECT id FROM knowledge_point WHERE name='概率' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='概率' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'true_false', '判断：若f(x)是定义在R上的奇函数，则必有f(0)=0。', '[]', '[""T""]', '由f(-0)=-f(0)得f(0)=-f(0)→f(0)=0。', 'easy', (SELECT id FROM knowledge_point WHERE name='函数' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='函数' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'true_false', '判断：等比数列的各项均不能为零。', '[]', '[""T""]', '等比数列定义要求公比q为常数，若某项为零则后续项均零导致公比不确定。', 'easy', (SELECT id FROM knowledge_point WHERE name='数列' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='数列' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'true_false', '判断：若a·b=0，则a=0或b=0。', '[]', '[""F""]', 'a·b=0表示两向量垂直，不一定为零向量。如a=(1,0),b=(0,1)。', 'easy', (SELECT id FROM knowledge_point WHERE name='向量' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='向量' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'true_false', '判断：互斥事件一定是对立事件。', '[]', '[""F""]', '对立事件必互斥，互斥不一定对立。如掷骰子：事件{1}与{2}互斥但不构成对立。', 'easy', (SELECT id FROM knowledge_point WHERE name='概率' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='概率' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'true_false', '判断：双曲线x²/4-y²/9=1的渐近线方程为y=±(2/3)x。', '[]', '[""F""]', '双曲线x²/a²-y²/b²=1的渐近线方程是y=±(b/a)x=±(3/2)x。', 'medium', (SELECT id FROM knowledge_point WHERE name='解析几何' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='解析几何' AND subject='math');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'multi_choice', '等差数列{an}中a₁>0，S₅=S₁₂，则下列说法正确的有', '["A. d<0", "B. S₁₇=0", "C. 当n=8或9时Sn取得最大值", "D. a₉=0"]', '["["A", "B", "C", "D"]"]', 'S₅=S₁₂→5a₁+10d=12a₁+66d→a₁=-8d。由a₁>0得d<0，A对。an=(n-9)d，a₉=0，D对。n<9时an>0，n>9时an<0，故S₈=S₉最大，C对。S₁₇=17(-8d)+136d=0，B对。', 'hard', (SELECT id FROM knowledge_point WHERE name='数列' AND subject='math' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='数列' AND subject='math');
